// GrowDoc Companion — Strain Database
// 530+ strains with practitioner-verified flower times (from flip, not first pistils).
// Lazy-loaded via dynamic import() — not imported at startup.
//
// Schema notes:
//   - flowerWeeks: measured from 12/12 flip, not from first pistils (add 7-14d to breeder numbers)
//   - isAuto: autoflower strains use totalDays (seed-to-harvest) as primary metric
//   - stretchRatio: height multiplier during flower stretch (1.0 = no stretch, 3.0 = triples)
//   - Strain IDs encode breeder when multiple versions exist (gelato-33-cookies vs gelato-barneys)

function s(name, breeder, fwMin, fwMax, srMin, srMax, sensitivities, type, opts = {}) {
  const entry = {
    name,
    breeder,
    flowerWeeks: { min: fwMin, max: fwMax },
    stretchRatio: { min: srMin, max: srMax },
    sensitivities,
    type,
    isAuto: false
  };
  if (opts.terps) entry.dominantTerpenes = opts.terps;
  if (opts.thc) entry.thcRange = opts.thc;
  if (opts.cbd) entry.cbdRange = opts.cbd;
  if (opts.desc) entry.description = opts.desc;
  return entry;
}

function auto(name, breeder, fwMin, fwMax, srMin, srMax, tdMin, tdMax, sensitivities, type, opts = {}) {
  const entry = s(name, breeder, fwMin, fwMax, srMin, srMax, sensitivities, type, opts);
  entry.isAuto = true;
  entry.totalDays = { min: tdMin, max: tdMax };
  return entry;
}

